const { ethers } = require("ethers");

// ABI fragments for ERC20 and DEX interactions
const ERC20_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function balanceOf(address owner) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)",
  "event Transfer(address indexed from, address indexed to, uint256 value)"
];

const DEX_ROUTER_ABI = [
  "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function swapTokensForExactTokens(uint256 amountOut, uint256 amountInMax, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function getAmountsOut(uint256 amountIn, address[] calldata path) view returns (uint256[] memory amounts)",
  "function getAmountsIn(uint256 amountOut, address[] calldata path) view returns (uint256[] memory amounts)",
  "function WETH() view returns (address)"
];

// Configuration
const CONFIG = {
  // Default slippage tolerance: 0.5%
  DEFAULT_SLIPPAGE_BPS: 50,
  // Maximum slippage tolerance: 5%
  MAX_SLIPPAGE_BPS: 500,
  // Transaction deadline: 20 minutes
  DEFAULT_DEADLINE_MINUTES: 20,
  // Approval buffer multiplier (approve 2x the needed amount instead of max uint256)
  APPROVAL_BUFFER_MULTIPLIER: 2,
  // Minimum approval threshold - if allowance is below this fraction of swap amount, re-approve
  REAPPROVAL_THRESHOLD: 0.1
};

class TokenSwapDApp {
  constructor(providerUrl, dexRouterAddress, chainId) {
    this.provider = new ethers.JsonRpcProvider(providerUrl);
    this.dexRouterAddress = dexRouterAddress;
    this.chainId = chainId;
    this.signer = null;
    this.routerContract = null;
    this.tokenCache = new Map();
    this.approvalHistory = new Map(); // Track approvals for monitoring
  }

  /**
   * Connect a wallet signer
   */
  async connectWallet(privateKeyOrSigner) {
    if (typeof privateKeyOrSigner === "string") {
      this.signer = new ethers.Wallet(privateKeyOrSigner, this.provider);
    } else {
      this.signer = privateKeyOrSigner;
    }

    this.routerContract = new ethers.Contract(
      this.dexRouterAddress,
      DEX_ROUTER_ABI,
      this.signer
    );

    const address = await this.signer.getAddress();
    console.log(`Wallet connected: ${address}`);
    return address;
  }

  /**
   * Connect using browser wallet (MetaMask, etc.)
   */
  async connectBrowserWallet() {
    if (typeof window === "undefined" || !window.ethereum) {
      throw new Error("No browser wallet detected");
    }

    const browserProvider = new ethers.BrowserProvider(window.ethereum);
    await browserProvider.send("eth_requestAccounts", []);
    this.signer = await browserProvider.getSigner();
    this.provider = browserProvider;

    this.routerContract = new ethers.Contract(
      this.dexRouterAddress,
      DEX_ROUTER_ABI,
      this.signer
    );

    const address = await this.signer.getAddress();
    console.log(`Browser wallet connected: ${address}`);
    return address;
  }

  /**
   * Get token information and cache it
   */
  async getTokenInfo(tokenAddress) {
    if (this.tokenCache.has(tokenAddress)) {
      return this.tokenCache.get(tokenAddress);
    }

    const contract = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);

    const [name, symbol, decimals] = await Promise.all([
      contract.name(),
      contract.symbol(),
      contract.decimals()
    ]);

    const tokenInfo = { address: tokenAddress, name, symbol, decimals, contract };
    this.tokenCache.set(tokenAddress, tokenInfo);
    return tokenInfo;
  }

  /**
   * Get token balance for an address
   */
  async getTokenBalance(tokenAddress, walletAddress = null) {
    const address = walletAddress || (await this.signer.getAddress());
    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const balance = await tokenInfo.contract.balanceOf(address);
    return {
      raw: balance,
      formatted: ethers.formatUnits(balance, tokenInfo.decimals),
      symbol: tokenInfo.symbol
    };
  }

  /**
   * Check current allowance for the DEX router
   */
  async checkAllowance(tokenAddress, ownerAddress = null) {
    const owner = ownerAddress || (await this.signer.getAddress());
    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const allowance = await tokenInfo.contract.allowance(owner, this.dexRouterAddress);
    return {
      raw: allowance,
      formatted: ethers.formatUnits(allowance, tokenInfo.decimals),
      symbol: tokenInfo.symbol
    };
  }

  /**
   * Calculate a safe approval amount based on the swap amount.
   * 
   * SECURITY: Instead of approving MaxUint256 (which gives the spender
   * unlimited access to your tokens forever), we approve only what's needed
   * with a reasonable buffer. This limits exposure if the DEX contract is
   * compromised or has a vulnerability.
   * 
   * The approval amount is: swapAmount * APPROVAL_BUFFER_MULTIPLIER
   * This allows for minor price fluctuations while keeping exposure limited.
   */
  calculateSafeApprovalAmount(swapAmount) {
    // Approve the exact amount needed plus a buffer for the current swap
    // Never approve MaxUint256 - this is a known DeFi anti-pattern that
    // exposes users to unlimited token drainage if the spender contract
    // is compromised
    const bufferedAmount = swapAmount * BigInt(CONFIG.APPROVAL_BUFFER_MULTIPLIER);
    return bufferedAmount;
  }

  /**
   * Approve tokens for the DEX router with a safe, bounded amount.
   * 
   * @param {string} tokenAddress - The ERC20 token to approve
   * @param {BigInt} requiredAmount - The amount needed for the current operation
   * @param {Object} options - Optional overrides
   * @param {boolean} options.exactAmount - If true, approve exactly the required amount (most secure)
   * @returns {Object} Transaction receipt and approval details
   */
  async approveToken(tokenAddress, requiredAmount, options = {}) {
    this._ensureSigner();

    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);
    const ownerAddress = await this.signer.getAddress();

    // Check current allowance
    const currentAllowance = await tokenContract.allowance(ownerAddress, this.dexRouterAddress);

    // If current allowance is sufficient, skip approval
    if (currentAllowance >= requiredAmount) {
      console.log(
        `Sufficient allowance exists for ${tokenInfo.symbol}: ` +
        `${ethers.formatUnits(currentAllowance, tokenInfo.decimals)} ` +
        `(need ${ethers.formatUnits(requiredAmount, tokenInfo.decimals)})`
      );
      return {
        alreadyApproved: true,
        currentAllowance: ethers.formatUnits(currentAllowance, tokenInfo.decimals),
        symbol: tokenInfo.symbol
      };
    }

    // Calculate safe approval amount
    let approvalAmount;
    if (options.exactAmount) {
      // Most secure: approve exactly what's needed
      approvalAmount = requiredAmount;
    } else {
      // Default: approve with a small buffer (2x) for convenience
      approvalAmount = this.calculateSafeApprovalAmount(requiredAmount);
    }

    console.log(
      `Approving ${ethers.formatUnits(approvalAmount, tokenInfo.decimals)} ` +
      `${tokenInfo.symbol} for DEX router`
    );

    // If there's an existing non-zero allowance, reset to 0 first
    // This is required by some tokens (like USDT) that don't allow
    // changing a non-zero allowance directly
    if (currentAllowance > 0n) {
      console.log(`Resetting existing allowance to 0 first (required by some tokens)`);
      const resetTx = await tokenContract.approve(this.dexRouterAddress, 0n);
      await resetTx.wait();
      console.log(`Allowance reset to 0`);
    }

    // Submit the approval transaction
    const tx = await tokenContract.approve(this.dexRouterAddress, approvalAmount);
    console.log(`Approval transaction submitted: ${tx.hash}`);

    const receipt = await tx.wait();

    // Track approval for monitoring/auditing
    this._trackApproval(tokenAddress, approvalAmount, tx.hash);

    // Verify the approval was set correctly
    const newAllowance = await tokenContract.allowance(ownerAddress, this.dexRouterAddress);
    if (newAllowance < requiredAmount) {
      throw new Error(
        `Approval verification failed: expected at least ` +
        `${ethers.formatUnits(requiredAmount, tokenInfo.decimals)} but got ` +
        `${ethers.formatUnits(newAllowance, tokenInfo.decimals)}`
      );
    }

    console.log(
      `Approval confirmed. New allowance: ` +
      `${ethers.formatUnits(newAllowance, tokenInfo.decimals)} ${tokenInfo.symbol}`
    );

    return {
      alreadyApproved: false,
      approvedAmount: ethers.formatUnits(approvalAmount, tokenInfo.decimals),
      newAllowance: ethers.formatUnits(newAllowance, tokenInfo.decimals),
      transactionHash: tx.hash,
      receipt,
      symbol: tokenInfo.symbol
    };
  }

  /**
   * Revoke approval for a token (set allowance to 0).
   * Users should revoke approvals for contracts they no longer use.
   */
  async revokeApproval(tokenAddress) {
    this._ensureSigner();

    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);

    const tx = await tokenContract.approve(this.dexRouterAddress, 0n);
    console.log(`Revocation transaction submitted for ${tokenInfo.symbol}: ${tx.hash}`);

    const receipt = await tx.wait();
    console.log(`Approval revoked for ${tokenInfo.symbol}`);

    return {
      transactionHash: tx.hash,
      receipt,
      symbol: tokenInfo.symbol
    };
  }

  /**
   * Get a quote for a token swap
   */
  async getSwapQuote(tokenInAddress, tokenOutAddress, amountIn, slippageBps = CONFIG.DEFAULT_SLIPPAGE_BPS) {
    if (slippageBps > CONFIG.MAX_SLIPPAGE_BPS) {
      throw new Error(
        `Slippage ${slippageBps / 100}% exceeds maximum allowed ${CONFIG.MAX_SLIPPAGE_BPS / 100}%`
      );
    }

    const tokenIn = await this.getTokenInfo(tokenInAddress);
    const tokenOut = await this.getTokenInfo(tokenOutAddress);

    const amountInWei = ethers.parseUnits(amountIn.toString(), tokenIn.decimals);
    const path = [tokenInAddress, tokenOutAddress];

    const routerReadOnly = new ethers.Contract(
      this.dexRouterAddress,
      DEX_ROUTER_ABI,
      this.provider
    );

    const amounts = await routerReadOnly.getAmountsOut(amountInWei, path);
    const amountOut = amounts[amounts.length - 1];

    // Calculate minimum output with slippage protection
    const amountOutMin = amountOut * (10000n - BigInt(slippageBps)) / 10000n;

    return {
      tokenIn: tokenIn.symbol,
      tokenOut: tokenOut.symbol,
      amountIn: ethers.formatUnits(amountInWei, tokenIn.decimals),
      amountOut: ethers.formatUnits(amountOut, tokenOut.decimals),
      amountOutMin: ethers.formatUnits(amountOutMin, tokenOut.decimals),
      amountInWei,
      amountOutWei: amountOut,
      amountOutMinWei: amountOutMin,
      slippageBps,
      priceImpact: this._calculatePriceImpact(amountInWei, amountOut, tokenIn.decimals, tokenOut.decimals),
      path
    };
  }

  /**
   * Execute a token swap with full approval flow
   */
  async swap(
    tokenInAddress,
    tokenOutAddress,
    amountIn,
    options = {}
  ) {
    this._ensureSigner();

    const {
      slippageBps = CONFIG.DEFAULT_SLIPPAGE_BPS,
      deadlineMinutes = CONFIG.DEFAULT_DEADLINE_MINUTES,
      recipient = null,
      exactApproval = false // Set to true for maximum security
    } = options;

    // Validate slippage
    if (slippageBps > CONFIG.MAX_SLIPPAGE_BPS) {
      throw new Error(
        `Slippage ${slippageBps / 100}% exceeds maximum allowed ${CONFIG.MAX_SLIPPAGE_BPS / 100}%`
      );
    }

    const signerAddress = await this.signer.getAddress();
    const toAddress = recipient || signerAddress;

    // Validate recipient address
    if (!ethers.isAddress(toAddress)) {
      throw new Error(`Invalid recipient address: ${toAddress}`);
    }

    console.log("\n=== Token Swap ===");

    // Step 1: Get token info
    const tokenIn = await this.getTokenInfo(tokenInAddress);
    const tokenOut = await this.getTokenInfo(tokenOutAddress);
    const amountInWei = ethers.parseUnits(amountIn.toString(), tokenIn.decimals);

    console.log(`Swapping ${amountIn} ${tokenIn.symbol} -> ${tokenOut.symbol}`);

    // Step 2: Check balance
    const balance = await tokenIn.contract.balanceOf(signerAddress);
    if (balance < amountInWei) {
      throw new Error(
        `Insufficient ${tokenIn.symbol} balance. ` +
        `Have: ${ethers.formatUnits(balance, tokenIn.decimals)}, ` +
        `Need: ${amountIn}`
      );
    }

    // Step 3: Get quote
    const quote = await this.getSwapQuote(tokenInAddress, tokenOutAddress, amountIn, slippageBps);
    console.log(`Expected output: ${quote.amountOut} ${tokenOut.symbol}`);
    console.log(`Minimum output (with ${slippageBps / 100}% slippage): ${quote.amountOutMin} ${tokenOut.symbol}`);

    // Step 4: Warn on high price impact
    if (quote.priceImpact > 3) {
      console.warn(`⚠️  HIGH PRICE IMPACT: ${quote.priceImpact.toFixed(2)}%`);
    }

    // Step 5: Handle approval with safe amounts (NOT MaxUint256)
    console.log("\n--- Approval Phase ---");
    const approvalResult = await this.approveToken(
      tokenInAddress,
      amountInWei,
      { exactAmount: exactApproval }
    );

    if (approvalResult.alreadyApproved) {
      console.log(`Using existing allowance`);
    } else {
      console.log(`New approval set: ${approvalResult.approvedAmount} ${tokenIn.symbol}`);
    }

    // Step 6: Execute swap
    console.log("\n--- Swap Phase ---");
    const deadline = Math.floor(Date.now() / 1000) + deadlineMinutes * 60;

    const tx = await this.routerContract.swapExactTokensForTokens(
      amountInWei,
      quote.amountOutMinWei,
      quote.path,
      toAddress,
      deadline
    );

    console.log(`Swap transaction submitted: ${tx.hash}`);
    const receipt = await tx.wait();
    console.log(`Swap confirmed in block ${receipt.blockNumber}`);

    // Step 7: Get final balances
    const finalBalanceIn = await this.getTokenBalance(tokenInAddress);
    const finalBalanceOut = await this.getTokenBalance(tokenOutAddress);

    const result = {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber,
      tokenIn: {
        symbol: tokenIn.symbol,
        amountSwapped: amountIn,
        remainingBalance: finalBalanceIn.formatted
      },
      tokenOut: {
        symbol: tokenOut.symbol,
        expectedAmount: quote.amountOut,
        minimumAmount: quote.amountOutMin,
        newBalance: finalBalanceOut.formatted
      },
      slippageBps,
      gasUsed: receipt.gasUsed.toString(),
      receipt
    };

    console.log("\n=== Swap Complete ===");
    console.log(`${tokenIn.symbol} balance: ${finalBalanceIn.formatted}`);
    console.log(`${tokenOut.symbol} balance: ${finalBalanceOut.formatted}`);

    return result;
  }

  /**
   * Review all active approvals for monitored tokens
   */
  async reviewApprovals(tokenAddresses) {
    this._ensureSigner();
    const ownerAddress = await this.signer.getAddress();

    console.log("\n=== Approval Review ===");
    const approvals = [];

    for (const tokenAddress of tokenAddresses) {
      const tokenInfo = await this.getTokenInfo(tokenAddress);
      const allowance = await tokenInfo.contract.allowance(ownerAddress, this.dexRouterAddress);

      const approvalInfo = {
        token: tokenInfo.symbol,
        address: tokenAddress,
        spender: this.dexRouterAddress,
        allowance: ethers.formatUnits(allowance, tokenInfo.decimals),
        allowanceRaw: allowance,
        isUnlimited: allowance === ethers.MaxUint256,
        hasApproval: allowance > 0n
      };

      if (approvalInfo.isUnlimited) {
        console.warn(
          `⚠️  UNLIMITED approval detected for ${tokenInfo.symbol}! ` +
          `Consider revoking with revokeApproval()`
        );
      } else if (approvalInfo.hasApproval) {
        console.log(
          `${tokenInfo.symbol}: ${approvalInfo.allowance} approved`
        );
      } else {
        console.log(`${tokenInfo.symbol}: No approval`);
      }

      approvals.push(approvalInfo);
    }

    return approvals;
  }

  /**
   * Batch revoke approvals for multiple tokens
   */
  async batchRevokeApprovals(tokenAddresses) {
    this._ensureSigner();

    console.log(`\nRevoking approvals for ${tokenAddresses.length} tokens...`);
    const results = [];

    for (const tokenAddress of tokenAddresses) {
      try {
        const result = await this.revokeApproval(tokenAddress);
        results.push({ tokenAddress, success: true, ...result });
      } catch (error) {
        console.error(`Failed to revoke approval for ${tokenAddress}: ${error.message}`);
        results.push({ tokenAddress, success: false, error: error.message });
      }
    }

    return results;
  }

  /**
   * Multi-hop swap through intermediate tokens
   */
  async swapMultiHop(
    tokenAddresses, // Array of token addresses forming the path
    amountIn,
    options = {}
  ) {
    this._ensureSigner();

    if (tokenAddresses.length < 2) {
      throw new Error("Path must contain at least 2 token addresses");
    }

    const {
      slippageBps = CONFIG.DEFAULT_SLIPPAGE_BPS,
      deadlineMinutes = CONFIG.DEFAULT_DEADLINE_MINUTES,
      recipient = null,
      exactApproval = false
    } = options;

    if (slippageBps > CONFIG.MAX_SLIPPAGE_BPS) {
      throw new Error(
        `Slippage ${slippageBps / 100}% exceeds maximum allowed ${CONFIG.MAX_SLIPPAGE_BPS / 100}%`
      );
    }

    const signerAddress = await this.signer.getAddress();
    const toAddress = recipient || signerAddress;

    const tokenIn = await this.getTokenInfo(tokenAddresses[0]);
    const tokenOut = await this.getTokenInfo(tokenAddresses[tokenAddresses.length - 1]);
    const amountInWei = ethers.parseUnits(amountIn.toString(), tokenIn.decimals);

    console.log(`\n=== Multi-Hop Swap ===`);
    const pathSymbols = [];
    for (const addr of tokenAddresses) {
      const info = await this.getTokenInfo(addr);
      pathSymbols.push(info.symbol);
    }
    console.log(`Path: ${pathSymbols.join(" -> ")}`);

    // Check balance
    const balance = await tokenIn.contract.balanceOf(signerAddress);
    if (balance < amountInWei) {
      throw new Error(
        `Insufficient ${tokenIn.symbol} balance. ` +
        `Have: ${ethers.formatUnits(balance, tokenIn.decimals)}, Need: ${amountIn}`
      );
    }

    // Get quote for multi-hop
    const routerReadOnly = new ethers.Contract(
      this.dexRouterAddress,
      DEX_ROUTER_ABI,
      this.provider
    );
    const amounts = await routerReadOnly.getAmountsOut(amountInWei, tokenAddresses);
    const amountOut = amounts[amounts.length - 1];
    const amountOutMin = amountOut * (10000n - BigInt(slippageBps)) / 10000n;

    console.log(`Expected output: ${ethers.formatUnits(amountOut, tokenOut.decimals)} ${tokenOut.symbol}`);
    console.log(`Minimum output: ${ethers.formatUnits(amountOutMin, tokenOut.decimals)} ${tokenOut.symbol}`);

    // Approve only the input token with safe amount
    await this.approveToken(
      tokenAddresses[0],
      amountInWei,
      { exactAmount: exactApproval }
    );

    // Execute multi-hop swap
    const deadline = Math.floor(Date.now() / 1000) + deadlineMinutes * 60;

    const tx = await this.routerContract.swapExactTokensForTokens(
      amountInWei,
      amountOutMin,
      tokenAddresses,
      toAddress,
      deadline
    );

    console.log(`Multi-hop swap transaction: ${tx.hash}`);
    const receipt = await tx.wait();
    console.log(`Confirmed in block ${receipt.blockNumber}`);

    return {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber,
      path: pathSymbols,
      amountIn: amountIn.toString(),
      expectedAmountOut: ethers.formatUnits(amountOut, tokenOut.decimals),
      minimumAmountOut: ethers.formatUnits(amountOutMin, tokenOut.decimals),
      gasUsed: receipt.gasUsed.toString(),
      receipt
    };
  }

  // --- Private helper methods ---

  _ensureSigner() {
    if (!this.signer) {
      throw new Error("No wallet connected. Call connectWallet() or connectBrowserWallet() first.");
    }
  }

  _trackApproval(tokenAddress, amount, txHash) {
    const key = `${tokenAddress}-${this.dexRouterAddress}`;
    const history = this.approvalHistory.get(key) || [];
    history.push({
      amount: amount.toString(),
      txHash,
      timestamp: Date.now(),
      isUnlimited: amount === ethers.MaxUint256
    });
    this.approvalHistory.set(key, history);
  }

  _calculatePriceImpact(amountIn, amountOut, decimalsIn, decimalsOut) {
    // Simplified price impact estimation
    const normalizedIn = Number(ethers.formatUnits(amountIn, decimalsIn));
    const normalizedOut = Number(ethers.formatUnits(amountOut, decimalsOut));
    if (normalizedIn === 0) return 0;
    // This is a rough estimate; real price impact requires pool reserve data
    return Math.abs(1 - normalizedOut / normalizedIn) * 100;
  }

  /**
   * Get approval history for auditing
   */
  getApprovalHistory(tokenAddress = null) {
    if (tokenAddress) {
      const key = `${tokenAddress}-${this.dexRouterAddress}`;
      return this.approvalHistory.get(key) || [];
    }
    return Object.fromEntries(this.approvalHistory);
  }
}

